const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, required = true, fallback) {
  const value = process.env[name] ?? fallback;
  if (required && (value === undefined || value === null || value === '')) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

const SENDGRID_API_KEY = getEnv('SENDGRID_API_KEY');
const TWILIO_ACCOUNT_SID = getEnv('TWILIO_ACCOUNT_SID');
const TWILIO_AUTH_TOKEN = getEnv('TWILIO_AUTH_TOKEN');
const DEFAULT_FROM_EMAIL = getEnv('DEFAULT_FROM_EMAIL', false, '');
const DEFAULT_FROM_PHONE = getEnv('DEFAULT_FROM_PHONE', false, '');

sgMail.setApiKey(SENDGRID_API_KEY);
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

function jsonResponse(res, status, body) {
  res.status(status).set('Content-Type', 'application/json').send(JSON.stringify(body));
}

function parseBody(req) {
  if (!req.body) return {};
  if (typeof req.body === 'string') {
    try {
      return JSON.parse(req.body);
    } catch {
      return {};
    }
  }
  return req.body;
}

function validateEmailPayload(email) {
  if (!email) return null;
  const to = email.to;
  const from = email.from || DEFAULT_FROM_EMAIL;
  const subject = email.subject;
  const text = email.text;
  const html = email.html;

  if (!to) throw new Error('email.to is required');
  if (!from) throw new Error('email.from is required or set DEFAULT_FROM_EMAIL');
  if (!subject) throw new Error('email.subject is required');
  if (!text && !html) throw new Error('email.text or email.html is required');

  return { to, from, subject, text, html };
}

function validateSmsPayload(sms) {
  if (!sms) return null;
  const to = sms.to;
  const from = sms.from || DEFAULT_FROM_PHONE;
  const body = sms.body;

  if (!to) throw new Error('sms.to is required');
  if (!from) throw new Error('sms.from is required or set DEFAULT_FROM_PHONE');
  if (!body) throw new Error('sms.body is required');

  return { to, from, body };
}

async function sendEmail(email) {
  const [response] = await sgMail.send({
    to: email.to,
    from: email.from,
    subject: email.subject,
    text: email.text,
    html: email.html
  });

  return {
    success: true,
    statusCode: response.statusCode,
    headers: response.headers
  };
}

async function sendSms(sms) {
  const message = await twilioClient.messages.create({
    to: sms.to,
    from: sms.from,
    body: sms.body
  });

  return {
    success: true,
    sid: message.sid,
    status: message.status,
    to: message.to,
    from: message.from
  };
}

functions.http('deliverMessage', async (req, res) => {
  if (req.method !== 'POST') {
    return jsonResponse(res, 405, { error: 'Method not allowed. Use POST.' });
  }

  try {
    const body = parseBody(req);
    const emailPayload = validateEmailPayload(body.email);
    const smsPayload = validateSmsPayload(body.sms);

    if (!emailPayload && !smsPayload) {
      return jsonResponse(res, 400, {
        error: 'Provide at least one of: email or sms'
      });
    }

    const result = {};
    const tasks = [];

    if (emailPayload) {
      tasks.push(
        sendEmail(emailPayload)
          .then((r) => {
            result.email = r;
          })
          .catch((err) => {
            result.email = {
              success: false,
              error: err.message,
              details: err.response && err.response.body ? err.response.body : undefined
            };
          })
      );
    }

    if (smsPayload) {
      tasks.push(
        sendSms(smsPayload)
          .then((r) => {
            result.sms = r;
          })
          .catch((err) => {
            result.sms = {
              success: false,
              error: err.message,
              code: err.code,
              moreInfo: err.moreInfo
            };
          })
      );
    }

    await Promise.all(tasks);

    const allSucceeded =
      (!result.email || result.email.success) &&
      (!result.sms || result.sms.success);

    return jsonResponse(res, allSucceeded ? 200 : 207, {
      success: allSucceeded,
      result
    });
  } catch (err) {
    return jsonResponse(res, 500, {
      success: false,
      error: err.message
    });
  }
});